  ('social-worker-moex-06174', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', 'Reamer建議社會工作者運用解決問題模式處理倫理兩難議題，首要之務為下列何者？', '["徵詢同儕專家意見", "釐清倫理議題", "透過腦力激盪提出各種可能解決問題的方案", "找出所有可能會被倫理抉擇所影響的個人、團體或組織"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "41e8b6db9ab9", "answer_pdf_sha1": "70e13f29cc63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
